package com.example.kinetic.data

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.OnConflictStrategy
import androidx.room.Query
import androidx.room.Update
import kotlinx.coroutines.flow.Flow

@Dao
interface ProfileDao {

    @Query("SELECT * FROM profiles ORDER BY createdAt ASC")
    fun getAllProfiles(): Flow<List<Profile>>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertProfile(profile: Profile): Long

    @Update
    suspend fun updateProfile(profile: Profile)

    @Delete
    suspend fun deleteProfile(profile: Profile)

    @Query("SELECT * FROM profile_settings WHERE profileId = :profileId")
    fun getProfileSettings(profileId: Long): Flow<ProfileSettings?>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun saveSettings(settings: ProfileSettings)

    @Query("SELECT * FROM exercises WHERE profileId = :profileId")
    fun getExercisesForProfile(profileId: Long): Flow<List<Exercise>>

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun saveExercise(exercise: Exercise)
}

package com.example.kinetic.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.room.migration.Migration
import androidx.sqlite.db.SupportSQLiteDatabase

@Database(
    entities = [Profile::class, ProfileSettings::class, Exercise::class],
    version = 2,
    exportSchema = false
)
abstract class AppDatabase : RoomDatabase() {

    abstract fun profileDao(): ProfileDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        private val MIGRATION_1_2 = object : Migration(1, 2) {
            override fun migrate(db: SupportSQLiteDatabase) {
                db.execSQL(
                    """
                    CREATE TABLE IF NOT EXISTS exercises (
                        id TEXT NOT NULL PRIMARY KEY,
                        profileId INTEGER NOT NULL,
                        workoutId TEXT NOT NULL,
                        weight REAL NOT NULL DEFAULT 0.0,
                        weightUnit TEXT NOT NULL DEFAULT 'KG',
                        FOREIGN KEY(profileId) REFERENCES profiles(id) ON DELETE CASCADE
                    )
                    """.trimIndent()
                )
                db.execSQL(
                    "CREATE INDEX IF NOT EXISTS index_exercises_profileId ON exercises(profileId)"
                )
                db.execSQL(
                    "ALTER TABLE profile_settings ADD COLUMN isHighContrastEnabled INTEGER NOT NULL DEFAULT 0"
                )
                db.execSQL(
                    "ALTER TABLE profile_settings ADD COLUMN isCardLayout INTEGER NOT NULL DEFAULT 1"
                )
            }
        }

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "kinetic_db"
                )
                    .addMigrations(MIGRATION_1_2)
                    .build()
                INSTANCE = instance
                instance
            }
        }
    }
}

package com.example.kinetic.ui.viewmodel

import android.app.Application
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.example.kinetic.data.AppDatabase
import com.example.kinetic.data.Exercise
import com.example.kinetic.data.Profile
import com.example.kinetic.data.ProfileRepository
import com.example.kinetic.data.ProfileSettings
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

class ProfileViewModel(application: Application) : AndroidViewModel(application) {

    private val repo = ProfileRepository(AppDatabase.getInstance(application).profileDao())

    val profiles: StateFlow<List<Profile>> = repo.allProfiles
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), emptyList())

    private val _selectedProfile = MutableStateFlow<Profile?>(null)
    val selectedProfile: StateFlow<Profile?> = _selectedProfile.asStateFlow()

    @OptIn(ExperimentalCoroutinesApi::class)
    val currentSettings: StateFlow<ProfileSettings?> = _selectedProfile
        .flatMapLatest { profile ->
            if (profile != null) repo.getSettings(profile.id) else flowOf(null)
        }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), null)

    @OptIn(ExperimentalCoroutinesApi::class)
    val currentExercises: StateFlow<Map<String, Exercise>> = _selectedProfile
        .flatMapLatest { profile ->
            if (profile != null)
                repo.getExercises(profile.id).map { list -> list.associateBy { it.workoutId } }
            else
                flowOf(emptyMap())
        }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5_000), emptyMap())

    fun selectProfile(profile: Profile) { _selectedProfile.value = profile }

    fun clearSelectedProfile() { _selectedProfile.value = null }

    fun addProfile(name: String) {
        if (name.isBlank()) return
        viewModelScope.launch { repo.addProfile(name) }
    }

    fun renameProfile(profile: Profile, newName: String) {
        if (newName.isBlank()) return
        viewModelScope.launch { repo.renameProfile(profile, newName) }
    }

    fun deleteProfile(profile: Profile) {
        viewModelScope.launch {
            repo.deleteProfile(profile)
            if (_selectedProfile.value?.id == profile.id) _selectedProfile.value = null
        }
    }

    fun updateSettings(settings: ProfileSettings) {
        viewModelScope.launch { repo.saveSettings(settings) }
    }

    fun saveExercise(exercise: Exercise) {
        viewModelScope.launch { repo.saveExercise(exercise) }
    }
}

